import sys
from math import gcd

input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    if n == 1:
        print(1)
        return

    d = [abs(a[i+1] - a[i]) for i in range(n-1)]

    best = 1
    # groups: list of (gcd_val, leftmost_start)
    groups = []

    for j, val in enumerate(d):
        new_groups = []
        for g, start in groups:
            ng = gcd(g, val)
            if new_groups and new_groups[-1][0] == ng:
                pass  # keep earliest start, which is already there
            else:
                new_groups.append((ng, start))
        # Add val itself starting at j
        if new_groups and new_groups[-1][0] == val:
            pass
        else:
            new_groups.append((val, j))
        groups = new_groups

        for g, start in groups:
            if g >= 2:
                length = j - start + 2  # subarray of d has length j-start+1, friend group is +1
                if length > best:
                    best = length

    print(best)

t = int(input())
for _ in range(t):
    solve()

